import AppKit

/// Platform brand lockups, rasterized from spotify-card's official SVGs and
/// embedded as base64 PNGs (no resource bundling). Used in the export card foot.
enum BrandLockup {
    /// Logical width/height ratio of each lockup (for layout).
    static func aspect(for source: SourceKind?) -> CGFloat {
        switch source {
        case .spotify: return 823.46 / 225.25
        case .appleMusic: return 83.0 / 20.0
        case .none: return 1
        }
    }

    static func image(for source: SourceKind?) -> NSImage? {
        let b64: String
        switch source {
        case .spotify: b64 = spotify
        case .appleMusic: b64 = appleMusic
        case .none: return nil
        }
        guard let data = Data(base64Encoded: b64) else { return nil }
        return NSImage(data: data)
    }

    private static let spotify = ""
    private static let appleMusic = ""
    static let qq = ""
}
